export interface Person {
  id: string;
  name: string;
  color: string;
  avatar?: string;
}

export enum ChoreFrequency {
  ONE_TIME = 'one-time',
  DAILY = 'daily',
  WEEKLY = 'weekly',
  MONTHLY = 'monthly',
  YEARLY = 'yearly',
}

export enum ChoreStatus {
  PENDING = 'pending',
  IN_PROGRESS = 'in-progress',
  COMPLETED = 'completed',
}

export enum ChorePriority {
  URGENT = 'urgent',
  SOON = 'soon',
  LATER = 'later',
  WHENEVER = 'whenever',
}

export interface Chore {
  id: string;
  title: string;
  description: string;
  frequency: ChoreFrequency;
  priority: ChorePriority;
  assigneeId: string; // can be empty string if unassigned
  status: ChoreStatus;
  completedAt?: number; // timestamp
  dueDate?: number; // timestamp (optional)
  createdAt: number; // timestamp
}

export interface AppState {
  people: Person[];
  chores: Chore[];
  loading: boolean;
}

import React, { useEffect, useState } from "react";
import { DragDropContext, Droppable, Draggable, DropResult } from "@hello-pangea/dnd";
import { Person, Chore, ChoreStatus, ChorePriority } from "../types";
import { subscribeToChores, subscribeToPeople, completeChore, updateChore } from "../services/dataService";
import { Calendar, User } from "lucide-react";
import ChoreModal from "../components/ChoreModal";
import { PRIORITY_CONFIG } from "../constants";

const KanbanBoard: React.FC = () => {
  const [chores, setChores] = useState<Chore[]>([]);
  const [people, setPeople] = useState<Person[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingChore, setEditingChore] = useState<Chore | undefined>(undefined);

  useEffect(() => {
    const unsubChores = subscribeToChores(setChores);
    const unsubPeople = subscribeToPeople(setPeople);
    return () => {
      unsubChores();
      unsubPeople();
    };
  }, []);

  const onDragEnd = async (result: DropResult) => {
    const { destination, source, draggableId } = result;

    if (!destination) return;
    if (destination.droppableId === source.droppableId && destination.index === source.index) return;

    const chore = chores.find((c) => c.id === draggableId);
    if (!chore) return;

    const destStatus = destination.droppableId as ChoreStatus;
    const sourceStatus = source.droppableId as ChoreStatus;

    // Handle completion logic
    if (destStatus === ChoreStatus.COMPLETED && sourceStatus !== ChoreStatus.COMPLETED) {
      await completeChore(chore);
    } 
    // Handle un-completion logic (move from Done back to Pending/In Progress)
    else if (destStatus !== ChoreStatus.COMPLETED && sourceStatus === ChoreStatus.COMPLETED) {
      await updateChore(chore.id, { status: destStatus, completedAt: undefined });
    } 
    // Handle Pending <-> In Progress
    else {
      await updateChore(chore.id, { status: destStatus });
    }
  };

  const getAssignee = (id: string) => people.find((p) => p.id === id);

  const handleEditChore = (chore: Chore) => {
    setEditingChore(chore);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingChore(undefined);
  };

  const columns = [
    { 
      id: ChoreStatus.PENDING, 
      title: "To Do", 
      bg: "bg-gray-100", 
      header: "border-t-4 border-blue-500",
      count: chores.filter((c) => c.status === ChoreStatus.PENDING).length
    },
    { 
      id: ChoreStatus.IN_PROGRESS, 
      title: "In Progress", 
      bg: "bg-yellow-50", 
      header: "border-t-4 border-yellow-500",
      count: chores.filter((c) => c.status === ChoreStatus.IN_PROGRESS).length
    },
    { 
      id: ChoreStatus.COMPLETED, 
      title: "Done", 
      bg: "bg-green-50", 
      header: "border-t-4 border-green-500",
      count: chores.filter((c) => c.status === ChoreStatus.COMPLETED).length
    },
  ];

  return (
    <div className="h-[calc(100vh-8rem)]">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Task Board</h1>
      </div>

      <DragDropContext onDragEnd={onDragEnd}>
        <div className="flex gap-6 h-full overflow-x-auto pb-4">
          {columns.map((col) => (
            <div key={col.id} className={`flex-1 min-w-[300px] flex flex-col rounded-xl ${col.bg} p-4`}>
              <div className={`bg-white p-3 rounded-lg shadow-sm mb-4 ${col.header} flex justify-between items-center`}>
                <h2 className="font-semibold text-gray-800">{col.title}</h2>
                <span className="bg-gray-100 text-gray-600 px-2 py-0.5 rounded-full text-xs font-bold">
                  {col.count}
                </span>
              </div>

              <Droppable droppableId={col.id}>
                {(provided) => (
                  <div
                    ref={provided.innerRef}
                    {...provided.droppableProps}
                    className="flex-1 overflow-y-auto space-y-3 min-h-[100px]"
                  >
                    {chores
                      .filter((c) => c.status === col.id)
                      .map((chore, index) => {
                        const assignee = getAssignee(chore.assigneeId);
                        const priorityConfig = PRIORITY_CONFIG[chore.priority] || PRIORITY_CONFIG[ChorePriority.SOON];

                        return (
                          <Draggable key={chore.id} draggableId={chore.id} index={index}>
                            {(provided, snapshot) => (
                              <div
                                ref={provided.innerRef}
                                {...provided.draggableProps}
                                {...provided.dragHandleProps}
                                onClick={() => handleEditChore(chore)}
                                className={`bg-white p-4 rounded-lg shadow-sm border border-gray-200 hover:shadow-md transition-shadow cursor-pointer ${
                                  snapshot.isDragging ? "rotate-2 scale-105" : ""
                                }`}
                                style={provided.draggableProps.style}
                              >
                                <div className="flex justify-between items-start mb-2">
                                  <h3 className="font-medium text-gray-900 leading-snug">{chore.title}</h3>
                                  <span className={`text-[10px] px-1.5 py-0.5 rounded border whitespace-nowrap ml-2 ${priorityConfig.class}`}>
                                    {priorityConfig.label}
                                  </span>
                                </div>

                                <div className="flex items-center justify-between text-xs text-gray-500 mt-3">
                                  <div className="flex items-center gap-2">
                                    {assignee ? (
                                      <div 
                                        className="w-6 h-6 rounded-full flex items-center justify-center text-white font-bold"
                                        style={{ backgroundColor: assignee.color }}
                                        title={assignee.name}
                                      >
                                        {assignee.name[0]}
                                      </div>
                                    ) : (
                                      <User className="w-5 h-5 text-gray-300" />
                                    )}
                                  </div>
                                  <div className="flex items-center gap-1">
                                     <Calendar className="w-3 h-3" />
                                     {chore.dueDate ? new Date(chore.dueDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric'}) : "No date"}
                                  </div>
                                </div>
                              </div>
                            )}
                          </Draggable>
                        );
                      })}
                    {provided.placeholder}
                  </div>
                )}
              </Droppable>
            </div>
          ))}
        </div>
      </DragDropContext>

      <ChoreModal 
        isOpen={isModalOpen} 
        onClose={handleCloseModal} 
        people={people} 
        existingChore={editingChore}
      />
    </div>
  );
};

export default KanbanBoard;

import React, { useEffect, useState } from "react";
import { Person, Chore, ChoreStatus, ChorePriority } from "../types";
import { subscribeToChores, subscribeToPeople, completeChore, deleteChore } from "../services/dataService";
import { CheckCircle2, Clock, Trash2, Plus, Calendar, AlertCircle } from "lucide-react";
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from "recharts";
import ChoreModal from "../components/ChoreModal";
import { PRIORITY_CONFIG } from "../constants";

const Dashboard: React.FC = () => {
  const [chores, setChores] = useState<Chore[]>([]);
  const [people, setPeople] = useState<Person[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingChore, setEditingChore] = useState<Chore | undefined>(undefined);

  useEffect(() => {
    const unsubChores = subscribeToChores(setChores);
    const unsubPeople = subscribeToPeople(setPeople);
    return () => {
      unsubChores();
      unsubPeople();
    };
  }, []);

  const pendingChores = chores.filter((c) => c.status === ChoreStatus.PENDING || c.status === ChoreStatus.IN_PROGRESS);
  const completedChores = chores.filter((c) => c.status === ChoreStatus.COMPLETED);

  // Chart Data: Tasks completed per person (approximation based on assigned tasks that are completed)
  const chartData = people.map(person => {
    const count = completedChores.filter(c => c.assigneeId === person.id).length;
    return { name: person.name, completed: count, color: person.color };
  });

  const getAssignee = (id: string) => people.find((p) => p.id === id);

  const handleAddChore = () => {
    setEditingChore(undefined);
    setIsModalOpen(true);
  };

  const handleEditChore = (chore: Chore) => {
    setEditingChore(chore);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingChore(undefined);
  };

  return (
    <div className="space-y-6">
      {/* Header Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-blue-100 text-blue-600 rounded-full">
              <Clock className="w-6 h-6" />
            </div>
            <div>
              <p className="text-sm text-gray-500">Active Tasks</p>
              <h3 className="text-2xl font-bold text-gray-900">{pendingChores.length}</h3>
            </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-green-100 text-green-600 rounded-full">
              <CheckCircle2 className="w-6 h-6" />
            </div>
            <div>
              <p className="text-sm text-gray-500">Completed</p>
              <h3 className="text-2xl font-bold text-gray-900">{completedChores.length}</h3>
            </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col justify-center">
           <button 
             onClick={handleAddChore}
             className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium transition-colors flex items-center justify-center gap-2"
           >
             <Plus className="w-5 h-5" />
             Add New Chore
           </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Task List */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-5 border-b border-gray-100 flex justify-between items-center">
            <h2 className="text-lg font-semibold text-gray-800">Upcoming Chores</h2>
          </div>
          <div className="divide-y divide-gray-100">
            {pendingChores.length === 0 ? (
               <div className="p-8 text-center text-gray-400">No active chores. You're all caught up!</div>
            ) : (
              pendingChores.map((chore) => {
                const assignee = getAssignee(chore.assigneeId);
                const priorityConfig = PRIORITY_CONFIG[chore.priority] || PRIORITY_CONFIG[ChorePriority.SOON];

                return (
                  <div 
                    key={chore.id} 
                    onClick={() => handleEditChore(chore)}
                    className="p-4 hover:bg-gray-50 transition-colors flex items-center justify-between group cursor-pointer"
                  >
                    <div className="flex items-center gap-4">
                      <button 
                        onClick={(e) => {
                          e.stopPropagation();
                          completeChore(chore);
                        }}
                        className="text-gray-300 hover:text-green-500 transition-colors"
                      >
                        <CheckCircle2 className="w-6 h-6" />
                      </button>
                      <div>
                        <div className="flex items-center gap-2">
                          <h4 className="font-medium text-gray-900">{chore.title}</h4>
                          <span className={`text-[10px] px-1.5 py-0.5 rounded border ${priorityConfig.class}`}>
                            {priorityConfig.label}
                          </span>
                          {chore.status === ChoreStatus.IN_PROGRESS && (
                             <span className="text-[10px] px-1.5 py-0.5 rounded border bg-yellow-100 text-yellow-700 border-yellow-200">
                               In Progress
                             </span>
                          )}
                        </div>
                        <div className="flex items-center gap-3 text-sm text-gray-500 mt-1 flex-wrap">
                          {assignee ? (
                            <div className="flex items-center gap-1.5">
                              <div 
                                className="w-5 h-5 rounded-full flex items-center justify-center text-[10px] text-white font-bold"
                                style={{ backgroundColor: assignee.color }}
                              >
                                {assignee.name[0]}
                              </div>
                              <span>{assignee.name}</span>
                            </div>
                          ) : (
                            <span className="text-gray-400 italic">Unassigned</span>
                          )}
                          <span className="flex items-center gap-1">
                            <Calendar className="w-3 h-3" />
                            {chore.dueDate ? new Date(chore.dueDate).toLocaleDateString() : "No due date"}
                          </span>
                          <span className="bg-gray-100 px-2 py-0.5 rounded text-xs capitalize">
                            {chore.frequency}
                          </span>
                        </div>
                      </div>
                    </div>
                    <button 
                      onClick={(e) => {
                        e.stopPropagation();
                        deleteChore(chore.id);
                      }}
                      className="text-gray-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                );
              })
            )}
          </div>
        </div>

        {/* Chart */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-5">
          <h2 className="text-lg font-semibold text-gray-800 mb-6">Completion Stats</h2>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <XAxis dataKey="name" tick={{fontSize: 12}} />
                <YAxis allowDecimals={false} />
                <Tooltip />
                <Bar dataKey="completed" radius={[4, 4, 0, 0]}>
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <ChoreModal 
        isOpen={isModalOpen} 
        onClose={handleCloseModal} 
        people={people} 
        existingChore={editingChore}
      />
    </div>
  );
};

export default Dashboard;

import React from "react";
