                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                );
              })
            )}
          </div>
        </div>

        {/* Chart */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-5">
          <h2 className="text-lg font-semibold text-gray-800 mb-6">Completion Stats</h2>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <XAxis dataKey="name" tick={{fontSize: 12}} />
                <YAxis allowDecimals={false} />
                <Tooltip />
                <Bar dataKey="completed" radius={[4, 4, 0, 0]}>
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <ChoreModal 
        isOpen={isModalOpen} 
        onClose={handleCloseModal} 
        people={people} 
        existingChore={editingChore}
      />
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from "react";
import { X, Sparkles } from "lucide-react";
import { Person, Chore, ChoreFrequency, ChoreStatus, ChorePriority } from "../types";
import { addChore, updateChore } from "../services/dataService";
import AIAssistant from "./AIAssistant";

interface ChoreModalProps {
  isOpen: boolean;
  onClose: () => void;
  people: Person[];
  existingChore?: Chore;
}

const ChoreModal: React.FC<ChoreModalProps> = ({ isOpen, onClose, people, existingChore }) => {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [frequency, setFrequency] = useState<ChoreFrequency>(ChoreFrequency.ONE_TIME);
  const [priority, setPriority] = useState<ChorePriority>(ChorePriority.SOON);
  const [assigneeId, setAssigneeId] = useState("");
  const [dueDate, setDueDate] = useState<string>("");
  const [showAI, setShowAI] = useState(false);

  useEffect(() => {
    if (existingChore) {
      setTitle(existingChore.title);
      setDescription(existingChore.description);
      setFrequency(existingChore.frequency);
      setPriority(existingChore.priority || ChorePriority.SOON);
      setAssigneeId(existingChore.assigneeId);
      setDueDate(existingChore.dueDate ? new Date(existingChore.dueDate).toISOString().split('T')[0] : "");
    } else {
      resetForm();
    }
  }, [existingChore, isOpen]);

  const resetForm = () => {
    setTitle("");
    setDescription("");
    setFrequency(ChoreFrequency.ONE_TIME);
    setPriority(ChorePriority.SOON);
    setAssigneeId("");
    setDueDate(""); // Default to no date
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const timestamp = dueDate ? new Date(dueDate).getTime() : undefined;

    const choreData = {
      title,
      description,
      frequency,
      priority,
      assigneeId,
      dueDate: timestamp
    };

    if (existingChore) {
      await updateChore(existingChore.id, choreData);
    } else {
      await addChore({
        ...choreData,
        status: ChoreStatus.PENDING,
        createdAt: Date.now(),
      });
    }
    onClose();
    resetForm();
  };

  const handleAISuggestion = (suggestion: { title: string, frequency: string }) => {
    setTitle(suggestion.title);
    setFrequency(suggestion.frequency as ChoreFrequency);
    setShowAI(false);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 p-4">
      <div className="bg-white rounded-xl shadow-xl w-full max-w-md flex flex-col max-h-[90vh]">
        <div className="flex justify-between items-center p-4 border-b border-gray-100 flex-shrink-0">
          <h2 className="text-lg font-semibold text-gray-900">
            {existingChore ? "Edit Chore" : "New Chore"}
          </h2>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-4 overflow-y-auto flex-1">
           {!existingChore && (
             <div className="mb-4">
               <button 
                 type="button"
                 onClick={() => setShowAI(!showAI)}
                 className="w-full flex items-center justify-center gap-2 py-2 px-4 bg-purple-50 text-purple-700 rounded-lg text-sm font-medium hover:bg-purple-100 transition-colors"
               >
                 <Sparkles className="w-4 h-4" />
                 {showAI ? "Hide AI Assistant" : "Ask AI for Ideas"}
               </button>
               {showAI && <AIAssistant onSelect={handleAISuggestion} />}
             </div>
           )}

          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Title</label>
              <input
                type="text"
                required
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                placeholder="e.g. Wash Dishes"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
              <textarea
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                placeholder="Optional details..."
                rows={2}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Frequency</label>
                <select
                  value={frequency}
                  onChange={(e) => setFrequency(e.target.value as ChoreFrequency)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                >
                  <option value={ChoreFrequency.ONE_TIME}>One-time</option>
                  <option value={ChoreFrequency.DAILY}>Daily</option>
                  <option value={ChoreFrequency.WEEKLY}>Weekly</option>
                  <option value={ChoreFrequency.MONTHLY}>Monthly</option>
                  <option value={ChoreFrequency.YEARLY}>Yearly</option>
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Priority</label>
                <select
                  value={priority}
                  onChange={(e) => setPriority(e.target.value as ChorePriority)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                >
                  <option value={ChorePriority.URGENT}>Urgent</option>
                  <option value={ChorePriority.SOON}>Do it soon</option>
                  <option value={ChorePriority.LATER}>Can wait</option>
                  <option value={ChorePriority.WHENEVER}>When you wish</option>
                </select>
              </div>
            </div>

            <div className="grid grid-cols-1 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Due Date <span className="text-gray-400 font-normal">(Optional)</span></label>
                <input
                  type="date"
                  value={dueDate}
                  onChange={(e) => setDueDate(e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Assignee</label>
              <select
                value={assigneeId}
                onChange={(e) => setAssigneeId(e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              >
                <option value="">Unassigned</option>
                {people.map((p) => (
                  <option key={p.id} value={p.id}>
                    {p.name}
                  </option>
                ))}
              </select>
            </div>

            <div className="pt-2 flex gap-3">
              <button
                type="button"
                onClick={onClose}
                className="flex-1 py-2 px-4 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors"
              >
                Cancel
              </button>
              <button
                type="submit"
                className="flex-1 py-2 px-4 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium"
              >
                {existingChore ? "Update" : "Create"}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default ChoreModal;

import React, { useEffect, useState, useRef } from "react";
import { DragDropContext, Droppable, Draggable, DropResult } from "@hello-pangea/dnd";
import { Person, Chore, ChoreStatus, ChorePriority } from "../types";
import { subscribeToChores, subscribeToPeople, completeChore, updateChore } from "../services/dataService";
import { Calendar, User } from "lucide-react";
import ChoreModal from "../components/ChoreModal";
import { PRIORITY_CONFIG } from "../constants";

const KanbanBoard: React.FC = () => {
  const [chores, setChores] = useState<Chore[]>([]);
  const [people, setPeople] = useState<Person[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingChore, setEditingChore] = useState<Chore | undefined>(undefined);

  const columnRefs = useRef<Record<string, HTMLDivElement | null>>({});

  useEffect(() => {
    const unsubChores = subscribeToChores(setChores);
    const unsubPeople = subscribeToPeople(setPeople);
    return () => {
      unsubChores();
      unsubPeople();
    };
  }, []);

  const onDragEnd = async (result: DropResult) => {
    const { destination, source, draggableId } = result;

    if (!destination) return;
    if (destination.droppableId === source.droppableId && destination.index === source.index) return;

    const chore = chores.find((c) => c.id === draggableId);
    if (!chore) return;

    const destStatus = destination.droppableId as ChoreStatus;
    const sourceStatus = source.droppableId as ChoreStatus;

    // Handle completion logic
    if (destStatus === ChoreStatus.COMPLETED && sourceStatus !== ChoreStatus.COMPLETED) {
      await completeChore(chore);
    } 
    // Handle un-completion logic (move from Done back to Pending/In Progress)
    else if (destStatus !== ChoreStatus.COMPLETED && sourceStatus === ChoreStatus.COMPLETED) {
      await updateChore(chore.id, { status: destStatus, completedAt: undefined });
    } 
    // Handle Pending <-> In Progress
    else {
      await updateChore(chore.id, { status: destStatus });
    }
  };

  const getAssignee = (id: string) => people.find((p) => p.id === id);

  const handleEditChore = (chore: Chore) => {
    setEditingChore(chore);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingChore(undefined);
  };

  const scrollToColumn = (columnId: string) => {
    const el = columnRefs.current[columnId];
    if (el) {
      el.scrollIntoView({ behavior: 'smooth', inline: 'center', block: 'nearest' });
    }
  };

  const columns = [
    { 
      id: ChoreStatus.PENDING, 
      title: "To Do", 
      bg: "bg-gray-100", 
      header: "border-t-4 border-blue-500",
      count: chores.filter((c) => c.status === ChoreStatus.PENDING).length
    },
    { 
      id: ChoreStatus.IN_PROGRESS, 
      title: "In Progress", 
      bg: "bg-yellow-50", 
      header: "border-t-4 border-yellow-500",
      count: chores.filter((c) => c.status === ChoreStatus.IN_PROGRESS).length
    },
    { 
      id: ChoreStatus.COMPLETED, 
      title: "Done", 
      bg: "bg-green-50", 
      header: "border-t-4 border-green-500",
      count: chores.filter((c) => c.status === ChoreStatus.COMPLETED).length
    },
  ];

  return (
    <div className="flex flex-col h-[calc(100dvh-9rem)] md:h-[calc(100vh-8rem)]">
      <div className="flex justify-between items-center mb-4 md:mb-6">
        <h1 className="text-xl md:text-2xl font-bold text-gray-900">Task Board</h1>
      </div>

      {/* Mobile Column Navigation Buttons */}
      <div className="md:hidden grid grid-cols-3 gap-2 mb-4 px-0.5">
        {columns.map((col) => (
          <button
            key={col.id}
            onClick={() => scrollToColumn(col.id)}
            className={`py-2 rounded-lg text-xs font-bold border-b-4 shadow-sm transition-all active:scale-95
              ${col.id === ChoreStatus.PENDING ? 'bg-blue-50 text-blue-700 border-blue-500' : ''}
              ${col.id === ChoreStatus.IN_PROGRESS ? 'bg-yellow-50 text-yellow-700 border-yellow-500' : ''}
              ${col.id === ChoreStatus.COMPLETED ? 'bg-green-50 text-green-700 border-green-500' : ''}
            `}
          >
            {col.title}
          </button>
        ))}
      </div>

      <DragDropContext onDragEnd={onDragEnd}>
        {/* Mobile: Snap scrolling, Desktop: Standard overflow */}
        <div className="flex-1 flex gap-4 md:gap-6 overflow-x-auto pb-4 snap-x snap-mandatory px-0.5 scrollbar-hide">
          {columns.map((col) => (
            <div 
              key={col.id}
              ref={(el) => { columnRefs.current[col.id] = el; }}
              className={`flex-shrink-0 w-[85vw] md:w-[320px] md:flex-1 flex flex-col rounded-xl ${col.bg} p-3 md:p-4 snap-center h-full`}
            >
              <div className={`bg-white p-3 rounded-lg shadow-sm mb-3 md:mb-4 ${col.header} flex justify-between items-center sticky top-0 z-10`}>
                <h2 className="font-semibold text-gray-800">{col.title}</h2>
                <span className="bg-gray-100 text-gray-600 px-2 py-0.5 rounded-full text-xs font-bold">
                  {col.count}
                </span>
              </div>

              <Droppable droppableId={col.id}>
                {(provided) => (
                  <div
                    ref={provided.innerRef}
                    {...provided.droppableProps}
                    className="flex-1 overflow-y-auto space-y-3 min-h-[100px] pr-1"
                  >
                    {chores
                      .filter((c) => c.status === col.id)
                      .map((chore, index) => {
                        const assignee = getAssignee(chore.assigneeId);
                        const priorityConfig = PRIORITY_CONFIG[chore.priority] || PRIORITY_CONFIG[ChorePriority.SOON];

                        return (
                          <Draggable key={chore.id} draggableId={chore.id} index={index}>
                            {(provided, snapshot) => (
                              <div
                                ref={provided.innerRef}
                                {...provided.draggableProps}
                                {...provided.dragHandleProps}
                                onClick={() => handleEditChore(chore)}
                                className={`bg-white p-3 md:p-4 rounded-lg shadow-sm border border-gray-200 hover:shadow-md transition-shadow cursor-pointer ${
                                  snapshot.isDragging ? "rotate-2 scale-105 z-50" : ""
                                }`}
                                style={provided.draggableProps.style}
                              >
                                <div className="flex justify-between items-start mb-2">
                                  <h3 className="font-medium text-gray-900 leading-snug text-sm md:text-base">{chore.title}</h3>
                                  <span className={`text-[10px] px-1.5 py-0.5 rounded border whitespace-nowrap ml-2 flex-shrink-0 ${priorityConfig.class}`}>
                                    {priorityConfig.label}
                                  </span>
                                </div>

                                <div className="flex items-center justify-between text-xs text-gray-500 mt-3">
                                  <div className="flex items-center gap-2">
                                    {assignee ? (
                                      <div 
                                        className="w-6 h-6 rounded-full flex items-center justify-center text-white font-bold"
                                        style={{ backgroundColor: assignee.color }}
                                        title={assignee.name}
                                      >
                                        {assignee.name[0]}
                                      </div>
                                    ) : (
                                      <User className="w-5 h-5 text-gray-300" />
                                    )}
                                  </div>
                                  <div className="flex items-center gap-1">
                                     <Calendar className="w-3 h-3" />
                                     {chore.dueDate ? new Date(chore.dueDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric'}) : "No date"}
                                  </div>
                                </div>
                              </div>
                            )}
                          </Draggable>
                        );
                      })}
                    {provided.placeholder}
                  </div>
                )}
              </Droppable>
            </div>
          ))}
        </div>
      </DragDropContext>

      <ChoreModal 
        isOpen={isModalOpen} 
        onClose={handleCloseModal} 
        people={people} 
        existingChore={editingChore}
      />
    </div>
  );
};

