export default KanbanBoard;

import { 
  collection, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  onSnapshot, 
  query, 
  orderBy
} from "firebase/firestore";
import { db, isFirebaseConfigured } from "../firebase";
import { getLocalChores, saveLocalChores, getLocalPeople, saveLocalPeople } from "./localStorage";
import { Chore, Person, ChoreFrequency, ChoreStatus, ChorePriority, ChoreDifficulty } from "../types";
import { addWeeks, addMonths, addDays, addYears } from "date-fns";
import { PRIORITY_WEIGHTS } from "../constants";

// Listeners type
type Unsubscribe = () => void;

// --- Helper Functions ---

const generateId = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  return Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);
};

const sortChores = (chores: Chore[]): Chore[] => {
  return chores.sort((a, b) => {
    // 1. Sort by Priority
    const weightA = PRIORITY_WEIGHTS[a.priority] ?? 99;
    const weightB = PRIORITY_WEIGHTS[b.priority] ?? 99;

    if (weightA !== weightB) {
      return weightA - weightB;
    }

    // 2. Sort by Due Date (Earliest first)
    if (a.dueDate && b.dueDate) return a.dueDate - b.dueDate;
    if (a.dueDate) return -1; 
    if (b.dueDate) return 1;

    return 0;
  });
};

// --- People Operations ---

export const subscribeToPeople = (callback: (people: Person[]) => void): Unsubscribe => {
  if (isFirebaseConfigured && db) {
    const q = query(collection(db, "people"), orderBy("name"));
    return onSnapshot(q, (snapshot) => {
      const people = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Person));
      callback(people);
    });
  } else {
    callback(getLocalPeople());
    const interval = setInterval(() => callback(getLocalPeople()), 1000);
    return () => clearInterval(interval);
  }
};

export const addPerson = async (person: Omit<Person, "id">) => {
  if (isFirebaseConfigured && db) {
    await addDoc(collection(db, "people"), person);
  } else {
    const people = getLocalPeople();
    const newPerson = { ...person, id: generateId() };
    saveLocalPeople([...people, newPerson]);
  }
};

export const deletePerson = async (id: string) => {
  if (isFirebaseConfigured && db) {
    await deleteDoc(doc(db, "people", id));
  } else {
    const people = getLocalPeople();
    saveLocalPeople(people.filter(p => p.id !== id));
  }
};

// --- Chore Operations ---

export const subscribeToChores = (callback: (chores: Chore[]) => void): Unsubscribe => {
  if (isFirebaseConfigured && db) {
    const q = query(collection(db, "chores"));
    return onSnapshot(q, (snapshot) => {
      const chores = snapshot.docs.map(doc => {
        const data = doc.data();
        return { 
          id: doc.id, 
          ...data,
          priority: data.priority || ChorePriority.SOON,
          difficulty: data.difficulty || ChoreDifficulty.MEDIUM
        } as Chore;
      });
      callback(sortChores(chores));
    });
  } else {
    const getAndSort = () => {
      const chores = getLocalChores();
      return sortChores(chores.map(c => ({
        ...c,
        priority: c.priority || ChorePriority.SOON,
        difficulty: c.difficulty || ChoreDifficulty.MEDIUM
      })));
    };
    callback(getAndSort());
    const interval = setInterval(() => callback(getAndSort()), 1000);
    return () => clearInterval(interval);
  }
};

export const addChore = async (chore: Omit<Chore, "id">) => {
  if (isFirebaseConfigured && db) {
    await addDoc(collection(db, "chores"), chore);
  } else {
    const chores = getLocalChores();
    const newChore = { ...chore, id: generateId() };
    saveLocalChores([...chores, newChore]);
  }
};

export const updateChore = async (id: string, updates: Partial<Chore>) => {
  if (isFirebaseConfigured && db) {
    await updateDoc(doc(db, "chores", id), updates);
  } else {
    const chores = getLocalChores();
    const updated = chores.map(c => c.id === id ? { ...c, ...updates } : c);
    saveLocalChores(updated);
  }
};

export const deleteChore = async (id: string) => {
  if (isFirebaseConfigured && db) {
    await deleteDoc(doc(db, "chores", id));
  } else {
    const chores = getLocalChores();
    saveLocalChores(chores.filter(c => c.id !== id));
  }
};

export const completeChore = async (chore: Chore) => {
  const now = Date.now();

  const { id, ...choreData } = chore;
  await updateChore(id, {
    ...choreData,
    status: ChoreStatus.COMPLETED,
    completedAt: now
  });

  if (chore.frequency !== ChoreFrequency.ONE_TIME) {
    const baseDate = chore.dueDate ? new Date(chore.dueDate) : new Date(now);
    let nextDueDate: number | undefined = undefined;

    if (chore.frequency === ChoreFrequency.DAILY) {
      nextDueDate = addDays(baseDate, 1).getTime();
    } else if (chore.frequency === ChoreFrequency.WEEKLY) {
      nextDueDate = addWeeks(baseDate, 1).getTime();
    } else if (chore.frequency === ChoreFrequency.MONTHLY) {
      nextDueDate = addMonths(baseDate, 1).getTime();
    } else if (chore.frequency === ChoreFrequency.YEARLY) {
      nextDueDate = addYears(baseDate, 1).getTime();
    }

    const newChore: Omit<Chore, "id"> = {
      title: chore.title,
      description: chore.description,
      frequency: chore.frequency,
      priority: chore.priority || ChorePriority.SOON,
      difficulty: chore.difficulty || ChoreDifficulty.MEDIUM,
      assigneeId: chore.assigneeId,
      status: ChoreStatus.PENDING,
      createdAt: now,
      checklist: chore.checklist ? chore.checklist.map(item => ({ ...item, id: generateId(), completed: false })) : undefined,
      ...(nextDueDate ? { dueDate: nextDueDate } : {})
    };

    await addChore(newChore);
  }
};

import React, { useEffect, useState } from "react";
import { Person, Chore, ChoreStatus, ChorePriority, ChoreDifficulty } from "../types";
import { subscribeToChores, subscribeToPeople, completeChore, deleteChore } from "../services/dataService";
import { CheckCircle2, Clock, Trash2, Plus, Calendar, Zap, ListChecks } from "lucide-react";
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from "recharts";
import ChoreModal from "../components/ChoreModal";
import { PRIORITY_CONFIG } from "../constants";

const Dashboard: React.FC = () => {
  const [chores, setChores] = useState<Chore[]>([]);
  const [people, setPeople] = useState<Person[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingChore, setEditingChore] = useState<Chore | undefined>(undefined);

  useEffect(() => {
    const unsubChores = subscribeToChores(setChores);
    const unsubPeople = subscribeToPeople(setPeople);
    return () => {
      unsubChores();
      unsubPeople();
    };
  }, []);

  const pendingChores = chores.filter((c) => c.status === ChoreStatus.PENDING || c.status === ChoreStatus.IN_PROGRESS);
  const completedChores = chores.filter((c) => c.status === ChoreStatus.COMPLETED);

  const chartData = people.map(person => {
    const count = completedChores.filter(c => c.assigneeId === person.id).length;
    return { name: person.name, completed: count, color: person.color };
  });

  const getAssignee = (id: string) => people.find((p) => p.id === id);

  const handleAddChore = () => {
    setEditingChore(undefined);
    setIsModalOpen(true);
  };

  const handleEditChore = (chore: Chore) => {
    setEditingChore(chore);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingChore(undefined);
  };

  const handleCompleteWithChecklist = async (e: React.MouseEvent, chore: Chore) => {
    e.preventDefault();
    e.stopPropagation();

    const hasUnfinished = chore.checklist?.some(item => !item.completed);

    if (hasUnfinished) {
      const confirmAll = window.confirm("The checklist is not fully completed. Mark all items as done and complete the task?");
      if (confirmAll) {
        const updatedChecklist = chore.checklist?.map(item => ({ ...item, completed: true }));
        await completeChore({ ...chore, checklist: updatedChecklist });
      }
    } else {
      await completeChore(chore);
    }
  };

  const getDifficultyColor = (diff: ChoreDifficulty) => {
    switch (diff) {
      case ChoreDifficulty.EASY: return 'text-green-600 bg-green-50 border-green-100';
      case ChoreDifficulty.MEDIUM: return 'text-orange-600 bg-orange-50 border-orange-100';
      case ChoreDifficulty.HARD: return 'text-red-600 bg-red-50 border-red-100';
      default: return 'text-gray-600 bg-gray-50 border-gray-100';
    }
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex items-center justify-between md:justify-start">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-blue-100 text-blue-600 rounded-full">
              <Clock className="w-6 h-6" />
            </div>
            <div>
              <p className="text-sm text-gray-500">Active Tasks</p>
              <h3 className="text-2xl font-bold text-gray-900">{pendingChores.length}</h3>
            </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex items-center justify-between md:justify-start">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-green-100 text-green-600 rounded-full">
              <CheckCircle2 className="w-6 h-6" />
            </div>
            <div>
              <p className="text-sm text-gray-500">Completed</p>
              <h3 className="text-2xl font-bold text-gray-900">{completedChores.length}</h3>
            </div>
          </div>
        </div>
        <div className="bg-white p-4 md:p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col justify-center">
           <button 
             type="button"
             onClick={handleAddChore}
             className="w-full py-3 bg-blue-600 hover:bg-blue-700 active:bg-blue-800 text-white rounded-lg font-medium transition-colors flex items-center justify-center gap-2 shadow-sm"
           >
             <Plus className="w-5 h-5" />
             Add New Chore
           </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-col">
          <div className="p-5 border-b border-gray-100 flex justify-between items-center">
            <h2 className="text-lg font-semibold text-gray-800">Upcoming Chores</h2>
          </div>
          <div className="divide-y divide-gray-100 overflow-y-auto max-h-[500px]">
            {pendingChores.length === 0 ? (
               <div className="p-8 text-center text-gray-400">No active chores. You're all caught up!</div>
            ) : (
              pendingChores.map((chore) => {
                const assignee = getAssignee(chore.assigneeId);
                const priorityConfig = PRIORITY_CONFIG[chore.priority] || PRIORITY_CONFIG[ChorePriority.SOON];

                const checklistTotal = chore.checklist?.length || 0;
                const checklistDone = chore.checklist?.filter(i => i.completed).length || 0;
                const progressPercent = checklistTotal > 0 ? (checklistDone / checklistTotal) * 100 : 0;

                return (
                  <div 
                    key={chore.id} 
                    onClick={() => handleEditChore(chore)}
                    className="p-4 hover:bg-gray-50 transition-colors flex items-center justify-between group cursor-pointer active:bg-gray-100"
                  >
                    <div className="flex items-center gap-3 md:gap-4 overflow-hidden flex-1">
                      <button 
                        type="button"
                        onClick={(e) => handleCompleteWithChecklist(e, chore)}
                        className="text-gray-400 hover:text-green-600 active:text-green-700 transition-colors flex-shrink-0 p-1"
                        title="Complete task"
                      >
                        <CheckCircle2 className="w-7 h-7" />
                      </button>
                      <div className="min-w-0 flex-1">
                        <div className="flex items-center gap-2 flex-wrap">
                          <h4 className="font-medium text-gray-900 truncate max-w-full">{chore.title}</h4>
                          <span className={`text-[10px] px-1.5 py-0.5 rounded border ${priorityConfig.class} whitespace-nowrap`}>
                            {priorityConfig.label}
                          </span>
                          <span className={`text-[10px] flex items-center gap-0.5 px-1.5 py-0.5 rounded border capitalize ${getDifficultyColor(chore.difficulty || ChoreDifficulty.MEDIUM)}`}>
                            <Zap className="w-2.5 h-2.5" />
                            {chore.difficulty || 'medium'}
                          </span>
                          {chore.status === ChoreStatus.IN_PROGRESS && (
                             <span className="text-[10px] px-1.5 py-0.5 rounded border bg-yellow-100 text-yellow-700 border-yellow-200 whitespace-nowrap">
                               In Progress
                             </span>
                          )}
                        </div>

                        {checklistTotal > 0 && (
                          <div className="mt-2 space-y-1">
                            <div className="flex items-center justify-between text-[10px] text-gray-400 font-bold">
                               <span className="flex items-center gap-1"><ListChecks className="w-3 h-3" /> {checklistDone}/{checklistTotal} Items</span>
                               <span>{Math.round(progressPercent)}%</span>
                            </div>
                            <div className="w-full h-1 bg-gray-100 rounded-full overflow-hidden">
                              <div 
                                className="h-full bg-blue-500 transition-all duration-500" 
                                style={{ width: `${progressPercent}%` }} 
                              />
                            </div>
                          </div>
                        )}

                        <div className="flex items-center gap-3 text-sm text-gray-500 mt-1.5 flex-wrap">
                          {assignee ? (
                            <div className="flex items-center gap-1.5">
                              <div 
                                className="w-5 h-5 rounded-full flex items-center justify-center text-[10px] text-white font-bold flex-shrink-0"
                                style={{ backgroundColor: assignee.color }}
                              >
                                {assignee.name[0]}
                              </div>
                              <span className="truncate max-w-[80px] md:max-w-none">{assignee.name}</span>
                            </div>
                          ) : (
                            <span className="text-gray-400 italic text-xs">Unassigned</span>
                          )}
                          <span className="flex items-center gap-1 text-xs md:text-sm">
                            <Calendar className="w-3 h-3" />
                            {chore.dueDate ? new Date(chore.dueDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric' }) : "--/--"}
                          </span>
                          <span className="bg-gray-100 px-2 py-0.5 rounded text-[10px] md:text-xs capitalize">
                            {chore.frequency}
                          </span>
                        </div>
                      </div>
                    </div>
                    <button 
                      type="button"
                      onClick={(e) => {
                        e.preventDefault();
                        e.stopPropagation();
                        if (window.confirm("Delete this chore permanently?")) {
                          deleteChore(chore.id);
                        }
                      }}
                      className="text-gray-300 hover:text-red-500 p-2 md:opacity-0 group-hover:opacity-100 transition-all ml-2"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                );
              })
            )}
          </div>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-5">
          <h2 className="text-lg font-semibold text-gray-800 mb-6">Completion Stats</h2>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <XAxis dataKey="name" tick={{fontSize: 12}} />
                <YAxis allowDecimals={false} />
                <Tooltip />
                <Bar dataKey="completed" radius={[4, 4, 0, 0]}>
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <ChoreModal 
        isOpen={isModalOpen} 
        onClose={handleCloseModal} 
        people={people} 
        existingChore={editingChore}
      />
    </div>
  );
};

export default Dashboard;

import React, { useEffect, useState, useRef, useMemo } from "react";
import { DragDropContext, Droppable, Draggable, DropResult } from "@hello-pangea/dnd";
import { Person, Chore, ChoreStatus, ChorePriority, ChoreDifficulty } from "../types";
import { subscribeToChores, subscribeToPeople, completeChore, updateChore } from "../services/dataService";
import { Calendar, User, ArrowRight, Check, Zap, ListChecks } from "lucide-react";
import ChoreModal from "../components/ChoreModal";
import { PRIORITY_CONFIG } from "../constants";

const KanbanBoard: React.FC = () => {
  const [chores, setChores] = useState<Chore[]>([]);
  const [people, setPeople] = useState<Person[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingChore, setEditingChore] = useState<Chore | undefined>(undefined);

  const columnRefs = useRef<Record<string, HTMLDivElement | null>>({});

  useEffect(() => {
    const unsubChores = subscribeToChores(setChores);
    const unsubPeople = subscribeToPeople(setPeople);
    return () => {
      unsubChores();
      unsubPeople();
    };
  }, []);

  const onDragEnd = async (result: DropResult) => {
    const { destination, source, draggableId } = result;

    if (!destination) return;
    if (destination.droppableId === source.droppableId && destination.index === source.index) return;

    const chore = chores.find((c) => c.id === draggableId);
    if (!chore) return;

    const destStatus = destination.droppableId as ChoreStatus;
    const sourceStatus = source.droppableId as ChoreStatus;

    if (destStatus === ChoreStatus.COMPLETED && sourceStatus !== ChoreStatus.COMPLETED) {
      const hasUnfinished = chore.checklist?.some(item => !item.completed);
      if (hasUnfinished) {
        if (window.confirm("The checklist is not fully completed. Mark all items as done and complete the task?")) {
          const updatedChecklist = chore.checklist?.map(item => ({ ...item, completed: true }));
          await completeChore({ ...chore, checklist: updatedChecklist });
        }
      } else {
        await completeChore(chore);
      }
    } 
    else if (destStatus !== ChoreStatus.COMPLETED && sourceStatus === ChoreStatus.COMPLETED) {
      await updateChore(chore.id, { status: destStatus, completedAt: undefined });
    } 
    else {
      await updateChore(chore.id, { status: destStatus });
    }
  };

  const handleAdvanceState = async (e: React.MouseEvent, chore: Chore) => {
    e.preventDefault();
    e.stopPropagation();

    if (chore.status === ChoreStatus.PENDING) {
      await updateChore(chore.id, { status: ChoreStatus.IN_PROGRESS });
    } else if (chore.status === ChoreStatus.IN_PROGRESS) {
      const hasUnfinished = chore.checklist?.some(item => !item.completed);
      if (hasUnfinished) {
        if (window.confirm("The checklist is not fully completed. Mark all items as done and complete the task?")) {
          const updatedChecklist = chore.checklist?.map(item => ({ ...item, completed: true }));
          await completeChore({ ...chore, checklist: updatedChecklist });
        }
      } else {
        await completeChore(chore);
      }
    }
  };

  const getAssignee = (id: string) => people.find((p) => p.id === id);

  const handleEditChore = (chore: Chore) => {
    setEditingChore(chore);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingChore(undefined);
  };

  const scrollToColumn = (columnId: string) => {
    const el = columnRefs.current[columnId];
    if (el) {
      el.scrollIntoView({ behavior: 'smooth', inline: 'center', block: 'nearest' });
    }
  };

  const getDifficultyColor = (diff: ChoreDifficulty) => {
    switch (diff) {
      case ChoreDifficulty.EASY: return 'text-green-600 bg-green-50 border-green-100';
      case ChoreDifficulty.MEDIUM: return 'text-orange-600 bg-orange-50 border-orange-100';
      case ChoreDifficulty.HARD: return 'text-red-600 bg-red-50 border-red-100';
      default: return 'text-gray-600 bg-gray-50 border-gray-100';
    }
  };

  const columns = useMemo(() => [
    { 
      id: ChoreStatus.PENDING, 
      title: "To Do", 
      bg: "bg-gray-100", 
      header: "border-t-4 border-blue-500",
      btnClass: "bg-blue-100 text-blue-700 border-blue-300",
      count: chores.filter((c) => c.status === ChoreStatus.PENDING).length
    },
    { 
      id: ChoreStatus.IN_PROGRESS, 
      title: "In Progress", 
      bg: "bg-yellow-50", 
      header: "border-t-4 border-yellow-500",
      btnClass: "bg-yellow-100 text-yellow-700 border-yellow-300",
      count: chores.filter((c) => c.status === ChoreStatus.IN_PROGRESS).length
    },
    { 
      id: ChoreStatus.COMPLETED, 
      title: "Done", 
      bg: "bg-green-50", 
      header: "border-t-4 border-green-500",
      btnClass: "bg-green-100 text-green-700 border-green-300",
      count: chores.filter((c) => c.status === ChoreStatus.COMPLETED).length
    },
  ], [chores]);

  return (
    <div className="flex flex-col h-[calc(100dvh-9rem)] md:h-[calc(100vh-8rem)] relative">
      <div className="flex justify-between items-center mb-4 md:mb-6">
        <h1 className="text-xl md:text-2xl font-bold text-gray-900">Task Board</h1>
      </div>

      <DragDropContext onDragEnd={onDragEnd}>
        <div className="flex-1 flex gap-4 md:gap-6 overflow-x-auto pb-24 md:pb-4 snap-x snap-mandatory px-0.5 scrollbar-hide">
          {columns.map((col) => (
            <div 
              key={col.id}
              ref={(el) => { columnRefs.current[col.id] = el; }}
              className={`flex-shrink-0 w-[85vw] md:w-[320px] md:flex-1 flex flex-col rounded-xl ${col.bg} p-3 md:p-4 snap-center h-full`}
            >
              <div className={`bg-white p-3 rounded-lg shadow-sm mb-3 md:mb-4 ${col.header} flex justify-between items-center sticky top-0 z-10`}>
                <h2 className="font-semibold text-gray-800">{col.title}</h2>
                <span className="bg-gray-100 text-gray-600 px-2 py-0.5 rounded-full text-xs font-bold">
                  {col.count}
                </span>
              </div>

              <Droppable droppableId={col.id}>
                {(provided) => (
                  <div
                    ref={provided.innerRef}
                    {...provided.droppableProps}
                    className="flex-1 overflow-y-auto space-y-3 min-h-[100px] pr-1"
                  >
                    {chores
                      .filter((c) => c.status === col.id)
                      .map((chore, index) => {
                        const assignee = getAssignee(chore.assigneeId);
                        const priorityConfig = PRIORITY_CONFIG[chore.priority] || PRIORITY_CONFIG[ChorePriority.SOON];

                        const checklistTotal = chore.checklist?.length || 0;
                        const checklistDone = chore.checklist?.filter(i => i.completed).length || 0;
                        const progressPercent = checklistTotal > 0 ? (checklistDone / checklistTotal) * 100 : 0;

                        return (
                          <Draggable key={chore.id} draggableId={chore.id} index={index}>
                            {(provided, snapshot) => (
                              <div
                                ref={provided.innerRef}
                                {...provided.draggableProps}
                                {...provided.dragHandleProps}
                                onClick={() => handleEditChore(chore)}
                                className={`bg-white p-3 md:p-4 rounded-lg shadow-sm border border-gray-200 hover:shadow-md transition-shadow cursor-pointer ${
                                  snapshot.isDragging ? "rotate-2 scale-105 z-50" : ""
                                }`}
                                style={provided.draggableProps.style}
                              >
                                <div className="flex justify-between items-start mb-2">
                                  <h3 className="font-medium text-gray-900 leading-snug text-sm md:text-base">{chore.title}</h3>
                                  <span className={`text-[10px] px-1.5 py-0.5 rounded border whitespace-nowrap ml-2 flex-shrink-0 ${priorityConfig.class}`}>
                                    {priorityConfig.label}
                                  </span>
                                </div>

                                <div className="flex gap-2 mb-2">
                                  <span className={`text-[10px] flex items-center gap-0.5 px-1.5 py-0.5 rounded border capitalize ${getDifficultyColor(chore.difficulty || ChoreDifficulty.MEDIUM)}`}>
                                    <Zap className="w-2.5 h-2.5" />
                                    {chore.difficulty || 'medium'}
                                  </span>
                                </div>

                                {checklistTotal > 0 && (
                                  <div className="mb-3">
                                    <div className="flex items-center justify-between text-[10px] text-gray-400 font-bold mb-1">
                                      <span className="flex items-center gap-1"><ListChecks className="w-3 h-3" /> {checklistDone}/{checklistTotal}</span>
                                      <span>{Math.round(progressPercent)}%</span>
                                    </div>
                                    <div className="w-full h-1 bg-gray-100 rounded-full overflow-hidden">
                                      <div 
                                        className="h-full bg-blue-500 transition-all duration-500" 
                                        style={{ width: `${progressPercent}%` }} 
                                      />
                                    </div>
                                  </div>
                                )}

                                <div className="flex items-center justify-between text-xs text-gray-500 mt-2">
                                  <div className="flex items-center gap-2">
                                    {assignee ? (
                                      <div 
                                        className="w-6 h-6 rounded-full flex items-center justify-center text-white font-bold"
                                        style={{ backgroundColor: assignee.color }}
                                        title={assignee.name}
                                      >
                                        {assignee.name[0]}
                                      </div>
                                    ) : (
                                      <User className="w-5 h-5 text-gray-300" />
                                    )}
                                    <div className="flex items-center gap-1 ml-2">
                                       <Calendar className="w-3 h-3" />
                                       {chore.dueDate ? new Date(chore.dueDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric'}) : "No date"}
                                    </div>
                                  </div>
                                </div>

                                {chore.status !== ChoreStatus.COMPLETED && (
                                  <div className="mt-3 pt-3 border-t border-gray-50 flex justify-end">
                                    <button
                                      type="button"
                                      onClick={(e) => handleAdvanceState(e, chore)}
                                      className={`text-xs flex items-center gap-1 px-4 py-2 rounded-full font-bold transition-all shadow-sm active:scale-95 ${
                                        chore.status === ChoreStatus.PENDING 
                                          ? "bg-blue-600 text-white hover:bg-blue-700" 
                                          : "bg-green-600 text-white hover:bg-green-700"
                                      }`}
                                    >
                                      {chore.status === ChoreStatus.PENDING ? "Start Task" : "Finish Task"}
                                      {chore.status === ChoreStatus.PENDING ? <ArrowRight className="w-4 h-4" /> : <Check className="w-4 h-4" />}
                                    </button>
                                  </div>
                                )}
                              </div>
                            )}
                          </Draggable>
                        );
                      })}
                    {provided.placeholder}
                  </div>
                )}
              </Droppable>
            </div>
          ))}
        </div>
      </DragDropContext>

      <div className="md:hidden fixed bottom-[4.5rem] left-0 right-0 px-4 z-20 flex justify-center pointer-events-none">
        <div className="flex gap-2 bg-white/95 backdrop-blur shadow-[0_4px_20px_rgba(0,0,0,0.15)] p-2 rounded-2xl border border-gray-100 pointer-events-auto">
          {columns.map((col) => (
            <button
              key={col.id}
              type="button"
              onClick={() => scrollToColumn(col.id)}
              className={`px-4 py-2 rounded-xl text-xs font-bold border-b-2 transition-all active:scale-95 ${col.btnClass}`}
            >
              {col.title}
            </button>
          ))}
        </div>
      </div>

      <ChoreModal 
        isOpen={isModalOpen} 
        onClose={handleCloseModal} 
        people={people} 
        existingChore={editingChore}
      />
    </div>
  );
};

export default KanbanBoard;

